      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
      AND slug != 'the-afternoon-show'
)
UPDATE radio_episodes SET show_id = (SELECT id FROM canonical)
WHERE show_id IN (SELECT id FROM dupes);

DELETE FROM radio_shows
WHERE external_id = '14'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
  AND slug != 'the-afternoon-show';

-- Audioasis (external_id = '1', canonical slug = 'audioasis')
WITH canonical AS (
    SELECT id FROM radio_shows
    WHERE slug = 'audioasis'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
), dupes AS (
    SELECT id FROM radio_shows
    WHERE external_id = '1'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
      AND slug != 'audioasis'
)
UPDATE radio_episodes SET show_id = (SELECT id FROM canonical)
WHERE show_id IN (SELECT id FROM dupes);

DELETE FROM radio_shows
WHERE external_id = '1'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
  AND slug != 'audioasis';

-- El Sonido (external_id = '2', canonical slug = 'el-sonido')
WITH canonical AS (
    SELECT id FROM radio_shows
    WHERE slug = 'el-sonido'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
), dupes AS (
    SELECT id FROM radio_shows
    WHERE external_id = '2'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
      AND slug != 'el-sonido'
