  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
  AND slug != 'el-sonido';

-- Midnight in a Perfect World (external_id = '5', canonical slug = 'midnight-in-a-perfect-world')
WITH canonical AS (
    SELECT id FROM radio_shows
    WHERE slug = 'midnight-in-a-perfect-world'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
), dupes AS (
    SELECT id FROM radio_shows
    WHERE external_id = '5'
      AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
      AND slug != 'midnight-in-a-perfect-world'
)
UPDATE radio_episodes SET show_id = (SELECT id FROM canonical)
WHERE show_id IN (SELECT id FROM dupes);

DELETE FROM radio_shows
WHERE external_id = '5'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp')
  AND slug != 'midnight-in-a-perfect-world';

-- Step 3: Also clean up any shows that were created with the OLD wrong external_ids
-- (1-6 mapped to the wrong shows). The seed set external_id='1' for Morning Show,
-- but the API's program 1 is Audioasis. After the DiscoverShows run, the seeded
-- Morning Show (external_id='1') had its name overwritten to "Audioasis". We already
-- fixed the external_id above; now restore the name for the seeded shows.
UPDATE radio_shows SET name = 'The Morning Show'
WHERE slug = 'the-morning-show'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

UPDATE radio_shows SET name = 'The Midday Show'
WHERE slug = 'the-midday-show'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

UPDATE radio_shows SET name = 'The Afternoon Show'
WHERE slug = 'the-afternoon-show'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

UPDATE radio_shows SET name = 'Audioasis'
WHERE slug = 'audioasis'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

UPDATE radio_shows SET name = 'El Sonido'
WHERE slug = 'el-sonido'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

UPDATE radio_shows SET name = 'Midnight in a Perfect World'
WHERE slug = 'midnight-in-a-perfect-world'
  AND station_id = (SELECT id FROM radio_stations WHERE slug = 'kexp');

-- Step 4: Add a unique index on (station_id, external_id) to prevent future
-- duplicates at the database level. The upsertRadioShow function already checks
-- this pair, but without a DB constraint, race conditions or bugs can still
-- create duplicates.
CREATE UNIQUE INDEX IF NOT EXISTS idx_radio_shows_station_external_id
ON radio_shows(station_id, external_id)
WHERE external_id IS NOT NULL;
